class Solution(object):
    def constructFromPrePost(self, preorder, postorder):
        post_map = {v: i for i, v in enumerate(postorder)}
        def build(pre_left, pre_right, post_left, post_right):
            if pre_left > pre_right:
                return None
            root = TreeNode(preorder[pre_left])
            if pre_left == pre_right:
                return root
            left_root_val = preorder[pre_left + 1]
            left_root_post_idx = post_map[left_root_val]
            left_size = left_root_post_idx - post_left + 1
            root.left = build(pre_left + 1, pre_left + left_size, post_left, left_root_post_idx)
            root.right = build(pre_left + left_size + 1, pre_right, left_root_post_idx + 1, post_right - 1)
            return root
        return build(0, len(preorder) - 1, 0, len(postorder) - 1)
